prabhu bale,—"sunaha sakala bhakta-gana e kupera jale ye karibe snana pana
satya satya haiba tara ganga-snana-phala
krsna-bhakti haiba tara раrата nirmala"',NULL,NULL),('cb.antya.3.253','cb','cb.antya.3','ЧБ Антья 3.253',253,NULL,'sarva bhakta-gana sri-mukhera vakya suni'' ucca kari'' balite lagila hari-dhvani',NULL,NULL),('cb.antya.3.254','cb','cb.antya.3','ЧБ Антья 3.254',254,NULL,'puri gosanira kupe sei divya jale snana pana kare prabhu maha-kutuhale',NULL,NULL),('cb.antya.3.255','cb','cb.antya.3','ЧБ Антья 3.255',255,NULL,'prabhu bale,—"ami ye achiye prthivite janiha kevala puri gosanira prite',NULL,NULL),('cb.antya.3.256','cb','cb.antya.3','ЧБ Антья 3.256',256,NULL,'puri gosanira ami—nahika anyatha puri vecile о ami vikai sarvatha',NULL,NULL),('cb.antya.3.257','cb','cb.antya.3','ЧБ Антья 3.257',257,NULL,'sakrt ye dekhe puri gosanire matra seha haibeka sri-krsnera prema-patra"',NULL,NULL),('cb.antya.3.258','cb','cb.antya.3','ЧБ Антья 3.258',258,NULL,'purira mahima tabe kahiya sabare kupa dhanya kari'' prabhu calila vasare',NULL,NULL),('cb.antya.3.259','cb','cb.antya.3','ЧБ Антья 3.259',259,NULL,'isvara se jane bhakta-mahima bada''te hena prabhu na bhaje krtaghna kоnа mate',NULL,NULL),('cb.antya.3.260','cb','cb.antya.3','ЧБ Антья 3.260',260,NULL,'bhakta-raksa lagi'' prabhu kare avatara
niravadhi bhakta-sange karena vihara',NULL,NULL),('cb.antya.3.261','cb','cb.antya.3','ЧБ Антья 3.261',261,NULL,'akartavya kare nija sevaka rakhite tara saksi vali vadhe sugriva-nimitte
bhakti-vatsalya prabhura ke pare kahite
akartavya kare prabhu sevaka rakhite',NULL,NULL),('cb.antya.3.262','cb','cb.antya.3','ЧБ Антья 3.262',262,NULL,'sevakera dasya prabhu kare nijanande ajaya caitanya-simha jine bhakta-vrnde',NULL,NULL),('cb.antya.3.263','cb','cb.antya.3','ЧБ Антья 3.263',263,NULL,'bhakta-gana-sange prabhu samudrera tire
sarva vaikunthadi-natha kirtane vihare',NULL,NULL),('cb.antya.3.264','cb','cb.antya.3','ЧБ Антья 3.264',264,NULL,'vasa karilena prabhu samudrera tire viharena prabhu bhakti-ananda-sagare',NULL,NULL),('cb.antya.3.265','cb','cb.antya.3','ЧБ Антья 3.265',265,NULL,'ei avatare sindhu krtartha haite ataeva laksmi janmilena taha haite',NULL,NULL),('cb.antya.3.266','cb','cb.antya.3','ЧБ Антья 3.266',266,NULL,'nilacala-vasira ye kichu papa haya ataeva sindhu-snane saba уaya ksaya',NULL,NULL),('cb.antya.3.267','cb','cb.antya.3','ЧБ Антья 3.267',267,NULL,'ataeva gangadevi vegavati haiya sei bhagye sindhu-majhe milila asiya',NULL,NULL),('cb.antya.3.268','cb','cb.antya.3','ЧБ Антья 3.268',268,NULL,'hena mate sindhu-tire sri-krsna-caitanya vaisena sakala mate sindhu kari'' dhanya',NULL,NULL),('cb.antya.3.269','cb','cb.antya.3','ЧБ Антья 3.269',269,NULL,'ye samaye isvara aila nilacale takhane prataparudra nahika utkale',NULL,NULL),('cb.antya.3.270','cb','cb.antya.3','ЧБ Антья 3.270',270,NULL,'yuddha-rase giyachena vijayanagare
ataeva prabhu na dekhila sei bare',NULL,NULL),('cb.antya.3.271','cb','cb.antya.3','ЧБ Антья 3.271',271,NULL,'thakura thakiya kata-dina nilacale punah gauda-dese ailena kutuhale',NULL,NULL);
INSERT OR REPLACE INTO verse_texts (id,verse_id,edition_id,translation,purport) VALUES ('cb.antya.3.144.ru','cb.antya.3.144','cb-ru','"Я очень доволен твоими объяснениями преданного служения".',NULL),('cb.antya.3.145.ru','cb.antya.3.145','cb-ru','"Всё сказанное тобой – истина. Да и как из твоих уст могло прозвучать что-либо иное?"
Стих 146-147
"Любой, кто будет слушать или читаь сто твоих стихов, непременно достигнет преданного служения Мне. Эти стихи прославятся как Сарвабхаума-шатака".
Другой вариант фразы йе хена кирти райа ("станут известны как"), это бали локе йена кайа ("люди назовут их").',NULL),('cb.antya.3.148.ru','cb.antya.3.148','cb-ru','"Никому не говори о форме, которуя Я проявил перед тобой. Храни это в своём сердце".
Стих 149-150
"Я приказываю тебе не разглашать этого, до тех пор, пока Я не покину этот мир.
Нитьянанда – Моё второе тело. С преданностью поклоняйся Его лотосным стопам".
Шри Гаурасундара сказал: "Пока Я нахожусь в этом мире, ты не должен уведомлять кого-либо об этом происшествии". К тому же Махапрабху поручил Сарвабхауме принять Шри Нитьянанду Прабху, как Верховную Личность Бога.',NULL),('cb.antya.3.151.ru','cb.antya.3.151','cb-ru','"Я заявляю, что Он очень серьёзен и вдумчив. Узнать Его человек может только тогда, когда Я представлю Его".
Слово тане означает "Его". Другой вариант для амара вачана ("Я объявляю"), является кехо нахи джане ("никто не знает Его").',NULL),('cb.antya.3.152.ru','cb.antya.3.152','cb-ru','Раскрыв эти истины Сарвабхауме, Господь скрыл Свою форму.',NULL),('cb.antya.3.153.ru','cb.antya.3.153','cb-ru','Когда Сарвабхаума Махашая узнал своего Господа, он потерял сознание и утонул в океане трансцендентного счастья.',NULL),('cb.antya.3.154.ru','cb.antya.3.154','cb-ru','Тот, кто слушает эти описания качеств Господа Чайтаньи, пересечёт океан материального существования и достигнет обители Господа Чайтаньи.',NULL),('cb.antya.3.155.ru','cb.antya.3.155','cb-ru','Эти повествования о Кришне в высшей степени сокровенны. Слушание их, без сомнений, позволит обрести Кришну.',NULL),('cb.antya.3.156.ru','cb.antya.3.156','cb-ru','И так, освободив Сарвабхауму, Господь с наслаждением продолжил Свои игры в киртан в Нилачале.',NULL),('cb.antya.3.157.ru','cb.antya.3.157','cb-ru','Господь был так поглощён вкусами любви к Кришне, танцуя и воспевая Его имена, что перестал различать день и ночь.',NULL),('cb.antya.3.158.ru','cb.antya.3.158','cb-ru','Когда жители Нилачалы видели эти изумительные игры, они подхватывали имена Хари и пели их вместе с преданными.',NULL),('cb.antya.3.159.ru','cb.antya.3.159','cb-ru','Они говорили: "Посмотрите, вот танцующий Джаганнатха". Никто не оставался равнодушным и все были сбиты с толку, глядя на Господа.
Господь Джаганнатха, Абсолютная Личность, представлен в форме деревянного Божества, установленного стационарно. Господь Гаурасундара – это танцующий Джаганнатха. Своими глазами увидев Верховного Господа, каждый забывал о материальных наслаждениях этого бренного мира.',NULL),('cb.antya.3.160.ru','cb.antya.3.160','cb-ru','Какой бы дорогой не следовал Шри Гаурасундара, везде люди постоянно повторяли имя Хари.',NULL),('cb.antya.3.161.ru','cb.antya.3.161','cb-ru','Куда бы не ступила нога Господа, там повсеместно люди собирали пыль.',NULL),('cb.antya.3.162.ru','cb.antya.3.162','cb-ru','Эту пыль собирали только благочестивые люди и их восторг не поддаётся никакому описанию.
Другое прочтение для лути ("похищать"), это гути ("частички").',NULL),('cb.antya.3.163.ru','cb.antya.3.163','cb-ru','Как обворожительна была бесподобная форма Господа! От одного взгляда на Него, замирали все очарованные сердца.
Слово анупама означает "бесподобный" или "несравненный". Другой вариант для выражения киба се шри-виграхера саундарья анупама ("какой сладкой была бесподобная форма Господа!"), это ки собха шри-виграхера саундарьяанупама, что означает по сути то же.',NULL),('cb.antya.3.164.ru','cb.antya.3.164','cb-ru','Слёзы экстатической любви постоянно текли из Его лотосных глаз, когда Его лотосные уста пели Харе Кришна маха-мантру.
В Шри-Чайтаньяаштаке (5), Шрипада Рупа Госвами написал:
"Шри Чайтанья Махапрабху повторяет Харе Кришна маха-мантру громким голосом. Святое имя танцует на Его языке, пока Его лучезарная рука ведёт счёт пропетым именам".',NULL),('cb.antya.3.165.ru','cb.antya.3.165','cb-ru','Всё Его тело было умащено сандаловой пастой и украшено цветочными гирляндами, а его плавная походка напоминала поступь опьянённого льва.
В Махабхарате (Дана-дхарма 149) говорится: суварна-варно хеманджо варанджас чанданаджади – "В Своих ранних играх Он появится как домохозяин с телом цвета золота. Его конечности будут прекрасны, а Его тело, умащённое сандаловой пастой, будет напоминать расплавленное золото".',NULL),('cb.antya.3.166.ru','cb.antya.3.166','cb-ru','Господь Чайтанья пребывал за пределами внешнего сознания, даже когда шёл по дороге, потому что был полностью поглощён вкусами преданного служения.',NULL),('cb.antya.3.167.ru','cb.antya.3.167','cb-ru','Через несколько дней, завершив паломничество по святым местам, вернулся Парамананда Пури.',NULL),('cb.antya.3.168.ru','cb.antya.3.168','cb-ru','Издалека увидев Парамананду Пури, Господь Гауранга почтительно поднялся.',NULL),('cb.antya.3.169.ru','cb.antya.3.169','cb-ru','Господь был очень рад увидеть Своего дорогого преданного. Он предложил ему Своё почтение, и в любвном восторге стал танцевать.',NULL),('cb.antya.3.170.ru','cb.antya.3.170','cb-ru','Господь поднял руки и воскликнул: "Хари! Хари! Наконец-то я увидел Парамананду Пури.',NULL),('cb.antya.3.171.ru','cb.antya.3.171','cb-ru','"Сегодня Мои глаза радуются, а Моя жизнь стала счастливой. Сегодня вся Моя духовная деятельность увенчалась успехом".
В этой связи следует обратиться к Шримад Бхагаватам (10.84.9-10
и 10.84.21). В Шри-Хари-бхакти-судходайе (13.2) сказано:
"Мой дорогой вайшнав, один взгляд на тебя дарит глядящему совершенное зрение, прикосновение к твоим лотосным стопам очищает чувства, а прославление твоих возвышенных качеств есть истинное занятие для языка, потому что в материальном мире очень трудно найти чистого преданного Господа".
В Чайтанья-чаритамрите (Мадхья 20.60) Чайтанья Махапрабху говорит следующее:
"Тот, кто видит тебя, прикасается к тебе или воспевает твои трансцендентные качества, использует свои чувства совершенным образом. Таков вердикт священных писаний".',NULL),('cb.antya.3.172.ru','cb.antya.3.172','cb-ru','Затем Господь сказал: "Сегодня, когда Шри Мадхавендра Пури предстал предо Мной, принятие Мной санньясы принесло свой плод".
Шри Парамананда Пури, который был близким учеником Шри Мадхавендры Пури, пробудил у Шри-Гаурасундары воспоминания о Шри Мадхавендре.',NULL),('cb.antya.3.173.ru','cb.antya.3.173','cb-ru','Произнеся эти слова, Господь обнял Своего дорогого преданного и увлажнил его тело слезами Своих лотосных глаз.
Слово синчилена означает "промокший".',NULL),('cb.antya.3.174.ru','cb.antya.3.174','cb-ru','Парамананда Пури тоже пришёл в восторг, и увидев луноподобное лицо Господа, совершенно забыл о себе.',NULL),('cb.antya.3.175.ru','cb.antya.3.175','cb-ru','Они долго предлагали друг другу своё почтение. Парамананда Пури был обителью любви Господа Чайтаньи.',NULL),('cb.antya.3.176.ru','cb.antya.3.176','cb-ru','Господь был чрезвычайно счастлив встретить Парамананду Пури, и заботился о нём, как о Своём спутнике.',NULL),('cb.antya.3.177.ru','cb.antya.3.177','cb-ru','Обретя своего Господа, Парамананда Пури остался в городе и с восторгом служил Его лотосным стопам.',NULL),('cb.antya.3.178.ru','cb.antya.3.178','cb-ru','Шри Парамананда Пури был дорогим учеником Шри Мадхавендры Пури, искушённым во вкусах экстатической любви.',NULL),('cb.antya.3.179.ru','cb.antya.3.179','cb-ru','Через несколько дней Сварупа Дамодара тоже присоединился к Господу в Нилачале и наслаждался играми с Господом днём и ночью.',NULL),('cb.antya.3.180.ru','cb.antya.3.180','cb-ru','Сварупа Дамодара был сведущ в музыкальном искусстве. Услышав его голос, Господь от радости начинал танцевать.',NULL),('cb.antya.3.181.ru','cb.antya.3.181','cb-ru','Сварупа Дамодара и Парамананда Пури были основными помощниками в заключительных играх Господа.
Шри Пурушоттама Бхаттачарья, который позже стал известен как Сварупа Дамодара, и Шри-Парамананда Пури, который был учеником Шри Мадхавендры Пури, достигли постоянного общения с Шри Гаурасундарой. Они стали основными спутниками Господа, потому что Махапрабху проводил с ними и день и ночь, слушая песни, прославляющие Шри Радха-Говинду из уст Сварупы Дамодары.',NULL),('cb.antya.3.182.ru','cb.antya.3.182','cb-ru','Таким образом, разные преданные постепенно присоединялись к Господу в Нилачале.',NULL),('cb.antya.3.183.ru','cb.antya.3.183','cb-ru','Все спутники Господа, которые приняли рождение в Ориссе, также постепенно присоединились к Нему.',NULL),('cb.antya.3.184.ru','cb.antya.3.184','cb-ru','Прадьюмна Мишра, тело которого было переполнено любовью к Богу, также как и Парамананда и Рамананда, двое самых серьёзных преданных – все присоединились к Господу.',NULL),('cb.antya.3.185.ru','cb.antya.3.185','cb-ru','Дамодара Пандита и Шри Шанкара Пандита тоже прибыли туда, спустя несколько дней.',NULL),('cb.antya.3.186.ru','cb.antya.3.186','cb-ru','Шри Прадьюмна Брахмачари был слугой Господа Нрисимхадевы, и Господь Нрисимха проявился в его теле.',NULL),('cb.antya.3.187.ru','cb.antya.3.187','cb-ru','Когда он понял что Нрисимхадева будет наслаждаться киртаном в образе санньяси, он пришёл и присоединился к Господу.',NULL),('cb.antya.3.188.ru','cb.antya.3.188','cb-ru','Великая личность, Бхагаван Ачарья, который и слышать не желал о материальных наслаждениях, тоже пришёл туда.
Шри Бхагаван Ачарья никогда не обсуждал темы, хоть как-то связанные с чувственными наслаждениями. Он слушал только о том, что связанно с именами, качествами и формами Господа Кришны.',NULL),('cb.antya.3.189.ru','cb.antya.3.189','cb-ru','Таким образом, слуги Господа из разных местностей собрались вместе и присоединились к Господу.',NULL),('cb.antya.3.190.ru','cb.antya.3.190','cb-ru','Как только они увидели Господа, все их страдания исчезли без следа, и все они включились в лилы киртана Господа.',NULL),('cb.antya.3.191.ru','cb.antya.3.191','cb-ru','Господь Вайкунтхи в образе санньяси, объединил всех Своих преданных киртаном.',NULL),('cb.antya.3.192.ru','cb.antya.3.192','cb-ru','Самый благоразумный Нитьянанда наслаждался вкусами нектарной любви к Господу Чайтанье. Он был в высшей степени независимым и не мог оставаться на одном месте.
Слово уддама означает "полностью независимый".',NULL),('cb.antya.3.193.ru','cb.antya.3.193','cb-ru','Когда Он порывался схватить и обнять Господа Джаганнатху, служители храма не могли Его удержать.
Фраза падихари-гане (произошло от искажения санскритского слова пратихари), означает "привратник" или "тот, кто наказывает лиц, совершающих сева-апарадху в отношении Господа Джаганнатхи"',NULL),('cb.antya.3.194.ru','cb.antya.3.194','cb-ru','Однажды Он взобрался на золотую симхасану и обнял Балараму.',NULL),('cb.antya.3.195.ru','cb.antya.3.195','cb-ru','Когда Он взобрался на асану, охранник храма схватил Его за руку, но в тот же миг отлетел обратно на расстояние пять-семь футов.',NULL),('cb.antya.3.196.ru','cb.antya.3.196','cb-ru','Нитьянанда Прабху снял гирлянду с шеи Баларамы и водрузил её на Себя.',NULL),('cb.antya.3.197.ru','cb.antya.3.197','cb-ru','Надев гирлянду, Нитьянанда походкой царя слонов вышел из храма. Охранник поднялся и задумался.',NULL),('cb.antya.3.198.ru','cb.antya.3.198','cb-ru','"Этот авадхута обладает нечеловеческой силой, иначе как объяснить, что Он остался жив, после того как коснулся Баларамы?"
Под словом авадхута подразумевается "санньяси".',NULL),('cb.antya.3.199.ru','cb.antya.3.199','cb-ru','"Я могу справиться с бешенным слоном, но как человек смог разорвать мою хватку?"',NULL),('cb.antya.3.200.ru','cb.antya.3.200','cb-ru','"Хотя я крепко схватил Его за руку, Он отбросил меня как травинку".',NULL),('cb.antya.3.201.ru','cb.antya.3.201','cb-ru','Так размышлял почтенный охранник. Когда позже он увидел Нитьянанду, то ощутил собственную ничтожность.',NULL),('cb.antya.3.202.ru','cb.antya.3.202','cb-ru','Тем не менее, Нитьянанда Сварупа, который по Своей природе был словно ребёнок, с любовью обнял охранника.',NULL),('cb.antya.3.203.ru','cb.antya.3.203','cb-ru','Через несколько дней после этих событий, Гаурачандра, супруг Лакшми, поселился на берегу океана.',NULL),('cb.antya.3.204.ru','cb.antya.3.204','cb-ru','Шри Гаурасундара был счастлив, глядя на этот очаровательный уголок океанского побережья.',NULL),('cb.antya.3.205.ru','cb.antya.3.205','cb-ru','Когда светила луна и дул южный ветерок, Шри Шачинандана вышел и сел на берегу океана.
Слово чандравати означает "наполнен лучами луны" или "освещён лунными лучами".',NULL),('cb.antya.3.206.ru','cb.antya.3.206','cb-ru','Лоб и всё тело Господа были умащены сандаловой пастой, а Его уста постоянно повторяли Харе Кришна маха-мантру.',NULL),('cb.antya.3.207.ru','cb.antya.3.207','cb-ru','Его грудь была украшена чудесными гирляндами из цветов, а со всех сторон Его окружали преданные.',NULL),('cb.antya.3.208.ru','cb.antya.3.208','cb-ru','Океанские волны в ночное время выглядят очень привлекательно. Господь смотрел на них и улыбался.',NULL),('cb.antya.3.209.ru','cb.antya.3.209','cb-ru','Теперь олицетворённый океан обрёл ту же удачу, которой достигли Ямуна и Ганга.
Гангадеви обрела свою удачу во времена игр Господа в Навадвипе. Йамунадеви достигла той же удачи во Вриндаванских играх Господа. Олицетворённый океан тоже обрёл свою удачу, равную достижениям этих двух богинь, когда Шри Гаурасундара поселился на его берегу.',NULL),('cb.antya.3.210.ru','cb.antya.3.210','cb-ru','Таким образом, Господь Вайкунтхи жил на берегу океана, вместе со Своими спутниками.',NULL),('cb.antya.3.211.ru','cb.antya.3.211','cb-ru','Господь счастливо проводил ночные киртаны в самом укромном месте на берегу океана.',NULL),('cb.antya.3.212.ru','cb.antya.3.212','cb-ru','Господь, который был мастером буйных танцев, танцевал теряя голову от вкусов собственной экстатической любви, а преданные купались в океане счастья.
Слово тандава означает "танцевать" или "энергичный танец" В Шримад Бхагаватам (10.16.26) говорится:
"Таким образом, Господь Кришна, изначальный учитель всех изящных искусств, принялся танцевать, а блеск драгоценных камней на головах змея, окрасил лотосные стопы Господа в багровые тона".',NULL),('cb.antya.3.213.ru','cb.antya.3.213','cb-ru','Каждое мгновение у Господа проявлялись всевозможные симптомы экстатической любви, как стоящие дыбом волосы, плачь, дрожь, гремкий рёв, испарина и изменение цвета кожи.',NULL),('cb.antya.3.214.ru','cb.antya.3.214','cb-ru','В теле Господа одновременно и в полной мере проявились все экстатические признаки преданного служения.',NULL),('cb.antya.3.215.ru','cb.antya.3.215','cb-ru','Все признаки экстаза преданного служения появились в олицетворённых формах. Они все полностью сознавали себя частями полных частей Господа.
Различные качества преданного служения приняли соответствующие им, полностью сознающие себя формы, которые занялись служением Господу. В материальном мире слово викара указывает на состояние отвращения или неприязни, но в отношении преданного служения Господу, викары преданного служения заслуживают уважения. Концепция викар непреданности, или концепция виварты, порицается Ведантой, но викары преданного служения – самые замечательные и трансцендентные.',NULL),('cb.antya.3.216.ru','cb.antya.3.216','cb-ru','Господь танцевал в настроении вайшнава. Сознавая это, все олицетворённые признаки экстаза преданного служения постоянно сопровождали Его.',NULL),('cb.antya.3.217.ru','cb.antya.3.217','cb-ru','Поэтому Шри Гаурасундару никогда, даже на мгновение, не оставляли чувства экстатической любви.',NULL),('cb.antya.3.218.ru','cb.antya.3.218','cb-ru','Даже когда эти признаки проявлялись Господом в играх очень скромно, они не имели себе равных.',NULL),('cb.antya.3.219.ru','cb.antya.3.219','cb-ru','Именно поэтому Его совершенства непостижимы и это вердикт всех Вед.
В Верховном Господе присутствуют все мыслимые и немыслимые энергии, и им нет счёта. Таково убеждение всех ведических писаний относительно Абсолютной Истины. В Шветашватара упанишад (6.8) сказано:
"Верховный Господь обладает всеми энергиями, которые действуют таким чудесным образом, что всё сознание, могущество и деятельность прямо подчинены исключительно Его воле". В Шветашватара упанишад (1.3) говорится:
"Те, кто медитируют на Верховную Личность Бога могут узреть Его скрытую божественную силу (чит-шакти)".
В Шримад-Бхагаватам (10.39.55) говорится:
"Кроме того, Господа окружают Его основные внутренние энергии – Шри, Пушти, Гир, Канти, Кирти, Тушти, Ила и Урджи, Его материальные энергии – Видья, Авидья и Майя, а также Его внутренняя энергия наслаждения – Шакти".',NULL),('cb.antya.3.220.ru','cb.antya.3.220','cb-ru','Любовь к Богу, которую проявлял Господь Чайтанья, не сможет проявить больше никто, во всех бесчисленных вселенных.
Во всём многообразии бесчисленных вселенных, не найдётся ничего подобного проявлению экстатической любви к Богу Шри Чайтаньядевой. Все объекты во вселенной предназначены для содействия в этом проявлении экстатической любви.',NULL),('cb.antya.3.221.ru','cb.antya.3.221','cb-ru','Поэтому никогда нельзя сравнивать Господа Чайтанью с кем-то, кроме Самого Господа.',NULL),('cb.antya.3.222.ru','cb.antya.3.222','cb-ru','Тот, на кого Он бросил Свой милостивый взгляд, уполномочен Им, и сможет понять Абсолютную Истину.',NULL),('cb.antya.3.223.ru','cb.antya.3.223','cb-ru','Поэтому, полностью предавшись Верховному Господу, человек обретает преданное служение и освобождается от всех заблуждений.
Принимая прибежище у Верховного Господа, живые существа полностью освобождаются от привязанности к материальным наслаждениям. В Бхагавад-гите (18.66) сказано:
"Не бойся, оставь все виды религии и просто предайся Мне. Я избавлю тебя от всех греховных реакций".
Смотрите также Шримад Бхагаватам (2.7.42).
Стих 224-225
Тот Господь, который управляет творением, и на которого постоянно медитируют такие личности, как Брахма и Шива, сейчас полностью поглощённый экстазом любви, танцевал в окружении преданных.',NULL),('cb.antya.3.226.ru','cb.antya.3.226','cb-ru','Я склоняюсь к стопам всех тех преданных, с которыми Гаурачандра наслаждался играми в киртан.',NULL),('cb.antya.3.227.ru','cb.antya.3.227','cb-ru','Так Шри Гаурасундара очаровательно танцевал всю ночь на берегу океана.',NULL),('cb.antya.3.228.ru','cb.antya.3.228','cb-ru','Гададхара постоянно был рядом с Господом. Они никогда и ни под каким предлогом не расставались.
Слово кати означает "чуть-чуть" или "никогда".',NULL),('cb.antya.3.229.ru','cb.antya.3.229','cb-ru','Гададхара всегда постоянно служил Господу – во время еды, сна и бодрствования.',NULL),('cb.antya.3.230.ru','cb.antya.3.230','cb-ru','Когда Гададхара читал для Него Шримад Бхагаватам, тот пьянел от вкусов экстатической любви.',NULL),('cb.antya.3.231.ru','cb.antya.3.231','cb-ru','Господь был доволен всем, что бы ни сказал Гададхара, и вместе с ним ходил в гости к вайшнавам.
Шри Гададхара Пандита Госвами всегда был рядом с Махапрабху, и на берегу океана радовал Гаурасундару пением и танцами всю ночь. Шри Гададхара Пандита Прабху никогда не разлучался с Господом. Во время, еды, сна или бодрствования, Гададхара Пандита Прабху всегда служил Господу. Он постоянно читал для Махапрабху Шримад Бхагаватам. Шри Гаурасундара всегда брал его с Собой, навещая вайшнавов.',NULL),('cb.antya.3.232.ru','cb.antya.3.232','cb-ru','Однажды Господь отправился в монастырь к Шри Парамананде Пури, где они сели побеседовать.',NULL),('cb.antya.3.233.ru','cb.antya.3.233','cb-ru','Господь испытывал к Парамананде Пури очень сильную привязанность, такую же, какая была между двумя близкими друзьями – Кришной и Арджуной.',NULL),('cb.antya.3.234.ru','cb.antya.3.234','cb-ru','Господь постоянно наслаждался обществом Парамананды Пури, беседуя с ним о Кришне.',NULL),('cb.antya.3.235.ru','cb.antya.3.235','cb-ru','Как всепроникающая Сверхдуша, Господь знал, что вода в водоёме Госвами Пури была испорченной.
Пруд Парамананды Пури находится немного к западу от храма Господа Джаганнатхи. Шримад Бхактивинода Тхакура нашёл местоположение этого водоёма, неподалёку от полицейского участка.',NULL),('cb.antya.3.236.ru','cb.antya.3.236','cb-ru','Господь спросил Госвами Пури, "Хороша ли вода в твоём водоёме?"',NULL),('cb.antya.3.237.ru','cb.antya.3.237','cb-ru','Парамананда Пури ответил: "Этот пруд какой-то неудачный, и вода в нём всегда сильно мутная".',NULL),('cb.antya.3.238.ru','cb.antya.3.238','cb-ru','Услышав это, Господь сказал, "Очень жаль, что Джаганнатха поскупился".',NULL),('cb.antya.3.239.ru','cb.antya.3.239','cb-ru','"Любой, кто коснётся воды из пруда Парамананды Пури, освободится, даже если он самый грешный из людей".',NULL),('cb.antya.3.240.ru','cb.antya.3.240','cb-ru','"По воле Господа Джаганнатхи вода стала настолько плохой, что её даже нельзя пить".',NULL),('cb.antya.3.241.ru','cb.antya.3.241','cb-ru','После этого Махапрабху поднялся, воздел вверх руки и сказал следующее.',NULL),('cb.antya.3.242.ru','cb.antya.3.242','cb-ru','"О Господь Джаганнатха, дай Мне благословение, чтобы Ганга смогла войти в этот пруд".',NULL),('cb.antya.3.243.ru','cb.antya.3.243','cb-ru','"Пожалуйста, прикажи Бхогавати Ганге, которая протекает вплоть до Паталалоки, войти в этот водоём".',NULL),('cb.antya.3.244.ru','cb.antya.3.244','cb-ru','Когда все преданные услышали слова, слетевшие с лотосных уст Господа, они громко запели имя Хари.',NULL),('cb.antya.3.245.ru','cb.antya.3.245','cb-ru','Спустя какое-то время Господь пошёл к Своему жилью, а преданные отправились отдыхать.',NULL),('cb.antya.3.246.ru','cb.antya.3.246','cb-ru','Тогда, исполняя приказ Господа, Гангадеви проникла в пруд.',NULL),('cb.antya.3.247.ru','cb.antya.3.247','cb-ru','Утром все стали свидетелями чуда – озерцо Парамананды Пури наполнилось кристально чистой водой.',NULL),('cb.antya.3.248.ru','cb.antya.3.248','cb-ru','Изумлённые преданные запели имя Хари, а Пури Госвами от восторга лишился сознания.',NULL),('cb.antya.3.249.ru','cb.antya.3.249','cb-ru','Когда все осознали, что Ганга вошла в водоём, они с почтением обошли его по кругу.
Слово виджайа означает "прибытие".',NULL),('cb.antya.3.250.ru','cb.antya.3.250','cb-ru','Как только Махапрабху услышал эту новость, Он пришёл туда и с радостью увидел чистую воду.
Стих 251-252
Господь сказал: "Послушайте преданные, любой, кто совершит омовение в водах этого водоёма, непременно достигнет плодов омовения в Ганге, и обретёт чистое преданное служение Кришне".',NULL),('cb.antya.3.253.ru','cb.antya.3.253','cb-ru','Когда преданные услышали эти слова из лотосных уст Господа, они начали громко воспевать имена Хари.',NULL),('cb.antya.3.254.ru','cb.antya.3.254','cb-ru','Потом Сам Господь с радостью принял омовение и испил эту божественную воду, вместе с Госвами Пури.',NULL),('cb.antya.3.255.ru','cb.antya.3.255','cb-ru','Господь сказал, "Я точно знаю, что пребываю в этом мире благодаря привязанности к Госвами Пури".',NULL),('cb.antya.3.256.ru','cb.antya.3.256','cb-ru','"Я – собственность Госвами Пури. В этом не может быть никаких сомнений. Если он пожелает, он может даже Меня продать".',NULL),('cb.antya.3.257.ru','cb.antya.3.257','cb-ru','"Тот, кому посчастливится хоть раз взглянуть на Госвами Пури, сможет обрести любовь к Кришне".
Слово сакрт означает "один раз".',NULL),('cb.antya.3.258.ru','cb.antya.3.258','cb-ru','После прославления Парамананды Пури и освящения его пруда, Господь вернулся на берег океана, к месту Своего проживания.',NULL),('cb.antya.3.259.ru','cb.antya.3.259','cb-ru','Только Верховный Господь знает, как увеличить славу Своих преданных. Таким образом, только неблагодарные не поклоняются Ему.
Смотри Шримад Бхагаватам (3.4.17
и 10.48.26).',NULL),('cb.antya.3.260.ru','cb.antya.3.260','cb-ru','Господь воплощается чтобы защитить Своих преданных и всегда наслаждается играми с ними.
Смотри Шримад Бхагаватам (10.14.20
и 3.2.13-16).',NULL),('cb.antya.3.261.ru','cb.antya.3.261','cb-ru','Ради блага Своих преданных, Господь иногда совершает поступки, которые кажутся неблаговидными. Примером этого может послужить убийство Вали по просьбе Сугривы.
Слово акартавья означает "то, что считается неприличным в этом материальном мире". Другой вариант этого стиха:
"Кто может описать любовь Господа к Своим преданным? Ради Своих преданных Господь совершает действия, которые могут казаться неблаговидными".',NULL),('cb.antya.3.262.ru','cb.antya.3.262','cb-ru','Преданные покоряют непобедимого, подобного льву Господа Чайтанью, а Господь служит Своим слугам, пребывая в полном экстазе.
Смотри Шримад Бхагаватам (10.86.59
и 10.9.19).',NULL),('cb.antya.3.263.ru','cb.antya.3.263','cb-ru','Властелин Вайкунтхи и всех других планетных систем, на берегу океана наслаждался киртаном с преданными.',NULL),('cb.antya.3.264.ru','cb.antya.3.264','cb-ru','Господь поселился на берегу океана и наслаждался экстатическим океаном преданного служения.',NULL),('cb.antya.3.265.ru','cb.antya.3.265','cb-ru','Поскольку океан достиг совершенства во время этого воплощения Господа, из его вод появилась Лакшми.
Поскольку Махапрабху в этой инкарнации хотел явиться в Нилачале, на берегу океана, Лакшмидеви приняла рождение как дочь океана.',NULL),('cb.antya.3.266.ru','cb.antya.3.266','cb-ru','Поэтому грехи, совершённые жителями Нилачалы, были уничтожены обычными омовениями в водах океана.',NULL),('cb.antya.3.267.ru','cb.antya.3.267','cb-ru','Благодаря такой удаче океана, Гангадеви стремительно несёт свои воды ему навстречу.',NULL),('cb.antya.3.268.ru','cb.antya.3.268','cb-ru','Таким образом, поселившись на берегу океана, Шри Кришна Чайтанья сделал его знаменитым.',NULL),('cb.antya.3.269.ru','cb.antya.3.269','cb-ru','Когда Господь пришёл в Нилачалу, царь Ориссы Махараджа Пратапарудра воевал за её пределами.',NULL),('cb.antya.3.270.ru','cb.antya.3.270','cb-ru','Он отправился в Виджая-нагару для ведения военных действий и потому не встретил Господа.
Когда Махапрабху прибыл в Нилачалу, Махараджа Пратапарудра отсутствовал. Он отправился на юг и воевал в Виджая-нагаре.',NULL),('cb.antya.3.271.ru','cb.antya.3.271','cb-ru','Проведя несколько дней в Нилачале, Господь ликуя вернулся в Гауда-деш.',NULL);